```json
{
  "global": "Define the canonical planet order, validate both input names, determine the index range between them, and extract intervening planets as a sorted tuple.",
  "subtasks": [
    {
      "subtask": "Establish the canonical ordering of planets from closest to farthest from the sun",
      "atomics": [
        "Create a data structure (list or tuple) containing all eight planets in solar distance order",
        "Ensure the ordering is: Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune"
      ]
    },
    {
      "subtask": "Validate that both input planet names are recognized",
      "atomics": [
        "Check if planet1 is a valid planet name in the canonical list",
        "Check if planet2 is a valid planet name in the canonical list",
        "Return an empty tuple immediately if either input is invalid"
      ]
    },
    {
      "subtask": "Determine the positional range between the two planets, accounting for either input order",
      "atomics": [
        "Look up the index position of planet1 in the canonical ordering",
        "Look up the index position of planet2 in the canonical ordering",
        "Compute the minimum and maximum indices to handle cases where planet1 is farther than planet2"
      ]
    },
    {
      "subtask": "Extract all planets strictly between the two input planets and return as a tuple",
      "atomics": [
        "Slice the planet list from min_index+1 to max_index (exclusive of endpoints)",
        "Convert the result to a tuple and return it"
      ]
    }
  ],
  "global_atomics": [
    "Verify correctness against all three provided examples",
    "Confirm that invalid planet names return an empty tuple"
  ],
  "gold_actions": {
    "global": "Initialize planets tuple as (Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune), validate both inputs exist in this tuple, compute min/max indices, return planets[min_idx+1:max_idx] as a tuple.",
    "subtasks": [
      {
        "subtask": "Create the ordered planets tuple",
        "atomics": [
          "Define planets = ('Mercury', 'Venus', 'Earth', 'Mars', 'Jupiter', 'Saturn', 'Uranus', 'Neptune')",
          "Verify tuple contains exactly 8 planets in heliocentric distance order"
        ]
      },
      {
        "subtask": "Validate both input planet names are in the planets tuple",
        "atomics": [
          "Check if planet1 in planets",
          "Check if planet2 in planets",
          "Return () if either check fails"
        ]
      },
      {
        "subtask": "Determine min and max indices from the two planet positions",
        "atomics": [
          "Compute idx1 = planets.index(planet1)",
          "Compute idx2 = planets.index(planet2)",
          "Compute min_idx = min(idx1, idx2) and max_idx = max(idx1, idx2)"
        ]
      },
      {
        "subtask": "Extract and return the intervening planets as a tuple",
        "atomics": [
          "Compute planets[min_idx + 1:max_idx] to get planets strictly between the two inputs",
          "Return the result (already a tuple slice)"
        ]
      }
    ],
    "global_atomics": [
      "Test bf('Jupiter', 'Neptune') returns ('Saturn', 'Uranus')",
      "Test bf('Earth', 'Mercury') returns ('Venus',)",
      "Test bf('Mercury', 'Uranus') returns ('Venus', 'Earth', 'Mars', 'Jupiter', 'Saturn')",
      "Test bf with invalid planet names returns ()"
    ]
  }
}
